import React from 'react';
import NovoRelatorioTVpA from './CadastroTVpAPage';
import MenuLateral from '../components/MenuLateral';


const PaginaCadastroTVpA = () => {
  return (
    <div style={{display:'flex'}}>
      <MenuLateral />
      <div style={{marginLeft:200, flex:1, minHeight:'100vh', background:'#f8f9fb', padding:'2rem'}}>
        {/* Exemplo de barra de topo fixa para TVpA */}
        <div style={{
          background:'#1976d2',
          borderRadius:'0 0 20px 20px',
          padding:'1.2rem 2rem 1.2rem 2rem',
          color:'#fff',
          position:'fixed',
          top:0,
          left:200,
          right:0,
          zIndex:101,
          boxShadow:'0 2px 8px #0001',
          maxWidth:1100,
          marginLeft:'auto',
          marginRight:'auto'
        }}>
          <h2 style={{margin:0,fontWeight:700}}>Novo Relatório TVpA</h2>
        </div>
        <div style={{marginTop:'110px'}}>
          <NovoRelatorioTVpA />
        </div>
      </div>
    </div>
  );
};

export default PaginaCadastroTVpA;
